mapper.select:
SELECT id, actor_id AS actorId, actor_type AS actorType, action, target_type AS targetType,
       target_id AS targetId, summary, ip, created_at AS createdAt
FROM audit_log
WHERE deleted=0
 AND actor_id=#{actor} 
 AND action=#{action} 
ORDER BY created_at DESC, id DESC
LIMIT #{limit}
